import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import App from './App';
import reportWebVitals from './common/test/reportWebVitals';
import {Router} from "react-router-dom";
import AppRoutes from "./routes/AppRoutes";
// import {GameProvider} from "./context/GameContext";

import { Provider } from 'react-redux';
import { store, persistor } from './store';
import {GoogleOAuthProvider} from "@react-oauth/google"; // Ensure Provider is imported from react-redux
import config from './common/config';
import {PersistGate} from "redux-persist/integration/react";  // 导入配置文件
const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(
  <React.StrictMode>
          <Provider store={store}>
              <PersistGate loading={null} persistor={persistor}>
              <GoogleOAuthProvider clientId={config.googleClientId}>
                  <App/>
              </GoogleOAuthProvider>
              </PersistGate>
          </Provider>
  </React.StrictMode>
);

// If you want to start measuring performance in your app, pass a function
// to log results (for example: reportWebVitals(console.log))
// or send to an analytics endpoint. Learn more: https://bit.ly/CRA-vitals
reportWebVitals();
